mapper.select:
select c.id, c.contract_no, c.contract_name, c.organ_id, c.sign_date, c.effect_date, c.expire_date, c.amount, c.status, c.attachments, c.remark, c.delete_flag, c.create_time, c.update_time, c.tonnage, c.audit_status, c.sign_status, s.supplier as organ_name, COALESCE(c.project_name, s.project_name) as project_name, dh.delivered_amount, dh.delivered_tonnage from jsh_contract c left join jsh_supplier s on c.organ_id = s.id left join ( select dh.organ_id, SUM(ifnull(dh.discount_last_money,0)+ifnull(dh.other_money,0)-ifnull(dh.deposit,0)) as delivered_amount, SUM(ifnull(di_sum.w,0)) as delivered_tonnage from jsh_depot_head dh left join ( select header_id, SUM(ifnull(weight,0)) as w from jsh_depot_item where ifnull(delete_flag,'0')!='1' group by header_id ) di_sum on di_sum.header_id = dh.id where dh.type='出库' and dh.sub_type='销售' and ifnull(dh.delete_flag,'0')!='1' group by dh.organ_id ) dh on dh.organ_id = c.organ_id where ifnull(c.delete_flag,'0') != '1'
and c.contract_no like concat('%', #{contractNo}, '%')
and c.contract_name like concat('%', #{contractName}, '%')
and c.organ_id = #{organId}
and c.audit_status = #{auditStatus}
and c.sign_status = #{signStatus}
order by c.create_time desc
